import re, json, textwrap

# find all sequences in parentheses
paren_spans = [(m.group(), m.start(), m.end()) for m in re.finditer(r"\(([^()]*)\)", text)]
# filter to Arabic letters etc (not numbers) roughly
def has_arabic(s):
    return any('\u0600' <= ch <= '\u06FF' for ch in s)
candidates = []
for s, start, end in paren_spans:
    inner = s[1:-1]
    if has_arabic(inner):
        candidates.append((inner.strip(), start+1, end-1))

len(candidates), candidates[:20]
